// app/page.tsx
import { Wallet } from "@prisma/client";
import { prisma } from "../lib/prisma"


export default async function Dashboard() {
  // Ambil semua dompet dari database
  const wallets = await prisma.wallet.findMany();

  return (
    <main className="p-10 bg-slate-50 min-h-screen">
      <h1 className="text-3xl font-bold mb-6 text-slate-800">Dashboard Keuangan</h1>
      
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {wallets.map((wallet: Wallet) => (
          <div key={wallet.id} className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <p className="text-sm text-slate-500 uppercase font-semibold">{wallet.type}</p>
            <h2 className="text-xl font-bold text-slate-700">{wallet.name}</h2>
            <p className="text-2xl mt-4 font-mono text-blue-600">
              Rp {wallet.balance.toLocaleString('id-ID')}
            </p>
          </div>
        ))}
      </div>

      <div className="mt-10 p-6 bg-blue-50 border border-blue-100 rounded-lg">
        <p className="text-blue-700 font-medium">
          💡 Data di atas diambil langsung dari PostgreSQL yang baru saja kamu isi lewat seed!
        </p>
      </div>
    </main>
  )
}